repoFiles.scripts/capture-boot.ps1:
$ErrorActionPreference = 'Stop'

$port = 'COM5'
$baud = 115200

$sp = New-Object System.IO.Ports.SerialPort $port, $baud
$sp.ReadTimeout = 15000
$sp.Open()

Start-Sleep -Seconds 2
$sp.DiscardInBuffer()

$log = ''
try {
    for ($i = 0; $i -lt 200; $i++) {
        $log += $sp.ReadLine() + "`n"
    }
} catch {
    # timeout is expected once boot output stops
}
$sp.Close()

if ($log -match 'bmp390: init ok') {
    Write-Output $log
    exit 0
} else {
    Write-Error 'barometer init marker not found in boot log'
    exit 1
}

repoFiles.scripts/symbol-gate.ps1:
$ErrorActionPreference = 'Stop'

$elf = 'build/sensor-firmware.elf'
if (-not (Test-Path $elf)) {
    Write-Error "build output not found at $elf"
    exit 1
}

$symbols = & xtensa-esp32-elf-nm $elf
if ($symbols -match 'bmp390_init') {
    Write-Output 'bmp390_init symbol present'
    exit 0
} else {
    Write-Error 'bmp390_init symbol is absent from the build; the driver is not linked in'
    exit 1
}
